INSERT INTO `tcatalogotramite` VALUES ('1.5.5.1.4.99','OTROS INGRESOS DIVESOS','OTROS INGRESOS DIVERSOS','00',0),('1551499','OTROS INGRESOS DIVERSOS','OTROS INGRESOS DIVERSOS','00',0),('DIV0111','REGISTRO DE INGRESO POR PENALIDES NO CONSENTIDAS ','REGISTRO DE INGRESO DE PENALIDADES NO CONSENTIDAS','00',0),('N/I','INGRESOS NO IDENTIFICADOS EN EL TUPA','INGRESOS NO IDENTIFICADOS EN EL TUPA','00',0),('PA884010D51','PAGO POR DERECHO A  OPTAR EL GRADO ACADEMICO DE BACHILLER','Procedimiento a través del cual el egresado solicita ser declarado Apto, para optar al Grado de Bachiller que otorga la UNDQT a nombre de la Nación.','00',1),('PA884010E2B','MATRÍCULA DE ALUMNO POR TRASLADO NACIONAL O INTERNACIONAL','Procedimiento mediante el cual el alumno solicita matrícula con traslado externo (Nacional o Internacional) proceso mediante el cual los estudiantes que se encuentran matriculados en una carrera o programa de Estudios de una Facultad de una Universidad, solicitan siempre que hayan culminado por lo menos el Primer Ciclo o Periodo Académico respectivo, para el cambio o traslado. La Dirección de la Escuela Profesional verifica el cumplimiento de los requisitos y emite la Resolución de traslado y procede con la matrícula.',NULL,1),('PA884011480','MATRÍCULA DE ALUMNO REGULAR','Procedimiento mediante el cual el alumno regular se matricula, el mismo que debe existir dentro del sistema y tener derecho de continuar en sus estudios en la universidad. Pierde esta condición si no cumple con los créditos mínimos o reprueba por segunda vez un ramo obligatorio. El Director del Centro de Computo verifica el cumplimiento de los requisitos y procede con la matrícula respectiva.',NULL,1),('PA884011BD7','DUPLICADO DE DIPLOMA DE GRADO O TÍTULO;  POR DETERIORO O MUTILACION DEL DIPLOMA ORIGINAL','Procedimiento mediante el cual el interesado solicita duplicado de Diploma de Grado o Título por deterioro o mutilación del diploma original, grado académico, título profesional o título de segunda especialidad, según sea el caso, por motivo de deterioro o mutilación del original. El decano de la facultad recibe la solicitud y lo deriva a secretaría General para su revisión en los Libros de Registro de Grados y Títulos de la Universidad quien después de verificar su conformidad emite informe al Consejo Universitario para que emita la resol. de Emisión y rotulado del Diploma con sello de DUPLICADO al margen izquierdo.','00',1),('PA88401229B','CONSTANCIA DE TERCIO, QUINTO Y DECIMO SUPERIOR','Procedimiento mediante el cual el alumno solicita constacia de Tercio, Quinto y Decimo Superior a través del cual, se deja constancia del orden de mérito basado en el promedio aritmético de semestre académico concluido, ocupado por el estudiante. El decano verifica el cumplimiento de los requisitos y autoriza la constancia.','00',1),('PA88401274B','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO EXTRAORDINARIO - DOS PRIMEROS PUESTOS DE EDUCACIÓN DE EDUCACIÓN SECUNDARIA','Tienen derecho a ingresar a la UNDQT, los alumnos que hayan obtenido los dos primeros puestos en orden de mérito en la Institución Educativa del que egresaron el año inmediato anterior de la región de Cusco, Madre de Dios, Apurímac, Puno, Arequipa, Moquegua y Tacna. Los postulantes que hayan obtenido los tres primeros puestos en orden de méritos deben rendir las pruebas de aptitud artística dirimente.','00',1),('PA884012A5C','EMISIÓN DE DIPLOMA DE TÍTULO PROFESIONAL (INCLUYE ROTULADO)','Procedimiento mediante el cual el administrado solicita la emisión de Diploma de Título Profesional. El Título Profesional de Licenciado o su equivalente que otorga la UNDQT se confiere a nombre de la Nación, cumpliendo las normas del reglamento. La acreditación que obtenga la UNDQT, reconocida por órgano competente se menciona en el Diploma respectivo. Se emite este documento previa evaluación y revisión de los requisitos exigidos.','00',1),('PA884013078','DESIGNACIÓN DE ASESOR PARA ESTUDIANTES EGRESADOS','Procedimiento a través del cual el aspirante al Título Profesional solicita designación de Asesor, quién es un profesor especialista en el tema de tesis elegido para la orientación y desarrollo del mismo, según esquema reglamentado (Plan de Tesis que pueden ir desarrollando los estudiantes matriculados que cursan el último semestre de estudios regulares).','00',1),('PA88401321E','DESIGNACIÓN DE DICTAMINANTES DE TESIS','Procedimiento a través del cual el trabajo de tesis es evaluado por los dictaminadores nombrados por Resolución del Decano, quienes emiten de manera individual informe fundamentado sobre la suficiencia y cumplimiento de los estándares de investigación propuesta, que permite establecer si el trabajo presentado está o no en condiciones de ser defendible en acto público.','00',1),('PA8840136A8','PAGO POR CURSO DIRIGIDO','Procedimiento mediante el cual el alumno paga por llevar cursos dirigidos, son aquellos que no se ofrecen en el semestre y son necesarios para los estudiantes que estén en condición de egresar. El Decano verifica el cumplimiento de los requisitos y la autoriza la matrícula a través de una Resolución, previo informe del Coordinador de la Carrera Profesional, verificando su condición por egresar, tiene derecho a matricularse hasta en tres cursos dirigidos.','00',1),('PA884013A51','REINICIO DE ESTUDIOS DE 1 A 4 SEMESTRES','Procedimiento mediante el cual el alumno solicita reinicio de estudios quien ha dejado de matricularse en uno o cuatro semestres. El Decano de la Facultad verifica el cumplimiento de los requisitos y autoriza la Resolución para el reinicio de estudios.','00',1),('PA884013B26','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO EXTRAORDINARIO  - ADMISION DE TITULADOS Y/O GRADUADOS','Los titulados de las Universidades y otros centros de educación superior con nivel universitario, que no sean de la UNDQT Están exonerados de la prueba de conocimientos y no de aptitud artística. Los titulados de la UNDQT, están exonerados de la prueba de aptitud artística y no de la prueba de conocimientos.','00',1),('PA884013DAB','EMISIÓN DE DIPLOMA DE SEGUNDA ESPECIALIDAD','Procedimiento a través del cual el graduando presenta un expediente con los documentos exigidos para obtener el Diploma de Segunda Especialidad Profesional. El personal especializado del Decanato de la Facultad revisa el cumplimiento de los requisitos exigidos y se le otorga el Diploma de segunda especialidad.','00',1),('PA884014358','CERTIFICADO DE ESTUDIOS (AÑOS ANTERIORES A 1995), COSTO POR SEMESTRE','Procedimiento mediante el cual el estudiante solicita su certificado de estudios, documento que proporciona información oficial sobre los promedios finales de las asignaturas del Plan de Estudios, cursadas por el estudiante en su Escuela Profesional. Se expide por semestre académico de años anteriores a 1995.','00',1),('PA88401484E','TRASLADO NACIONAL','Traslado Nacional es un procedimiento mediante le cual una persona natural solicita a la institución el traslado de sede de estudios de una Universidad o Escuela de Arte con rango Universitario, siempre que se cumpla con los requisitos exigidos en el TUPA o el el Reglamento Interno correspondiente, debiendo ser calificado por el Consejo Universitario',NULL,1),('PA8840148B7','TRASLADO INTERNACIONAL','Procedimiento mediante el cual un estudiante solicita traslado de una Universidad Extranjera a escuelas profesionales de la UNDQT. Este proceso se efectuará solo una vez al inicio del año. La postulación a traslado externo sólo es procedente para la misma especialidad o su equivalente que se cursó en la universidad de origen. El Vicerrectorado Académico verifica el cumplimiento de los requisitos y emite una Resolución.',NULL,1),('PA884015643','INSCRIPCIÓN AL PROCESO DE ADMISION POR CONCURSO EXTRAORDINARIO -DEPORTISTAS CALIFICADOS DESTACADOS','Procedimiento mediante el cual los estudiantes de la Región tienen Derecho a postular en esta modalidad, de conformidad a la Ley de Promoción y Desarrollo del Deporte Nº 28036 y la Directiva Nº004-PE-IPD-2001, que hayan concluido estudios secundarios. Se considera deportista calificado no profesional al postulante que participó a nivel Local, Regional, Nacional y/o Internacional, reconocido por la Federación correspondiente.','00',1),('PA884015DE7','SUBSANACIÓN DE ASIGNATURAS (CIENCIAS Y HUMANIDADES)','Procedimiento a través del cual el estudiante en situación por egresar tiene la opción de subsanar un máximo de dos(2) asignaturas desaprobadas en las asignaturas de Ciencias y Humanidades, con promedio mínimo de 10 puntos para completar el currículo de estudios y número de créditos exigidos para optar al Grado de Bachiller. El expediente y la Resolución que autoriza el examen extemporaneo firmado por el Decano de la Facultad quién verifica el cumplimiento de los requisitos y remite al Vice Rector Académico para emisión de la Resolución de Subsanación.','00',1),('PA88401642E','INSCRIPCIÓN AL PROCESO DE ADMISION POR CONCURSO EXTRAORDINARIO  - ADMISION DE ALUM.NOS DEL CENTRO DE PREPARACION PREUNIVERSITARIA - CPRUA','Procedimiento a través del cual, a los estudiantes secundarios que cumplen con realizar un ciclo de estudios preuniversitarios ofrecido por la UNDQT con rigor académico, se les adjudica una plaza vacante en acto público. Estudiantes que ingresan a la UNDQT sin el requisito de la Prueba de Concurso de Admisión Ordinario Tiene derecho a ingresar a la UNDQT, sin rendir la prueba de conocimientos y aptitud artística, los alumnos del Centro de Preparación Pre Universitaria','00',1),('PA884016454','PAGO ADICIONAL POR MATRÍCULA EXTEMPORANEA','Procedimiento mediante el cual el alumno solicita matrícula extemporánea esta empieza cuando termina la de matrícula regular. Y es el periodo donde todavía puede matricularse en cursos. El Director del Centro de Computo verifica el cumplimiento de los requisitos y procede a matrícula extemporánea.',NULL,1),('PA884016DF5','HOMOLOGACIÓN DE ASIGNATURAS','Procedimiento mediante el cual el administrado solicita homologación de asignaturas, mecanismo mediante el cual la Universidad con previo estudio de un profesor del área del curso que se pretende homologar y con el aval del director de programa al cual pertenece la asignatura hace equivalente una asignatura aprobada en la Universidad o en otra institución también se puede decir que es el reconocimiento traducido en número de créditos de los estudios realizados por el estudiante en determinada asignatura aprobada por otra que tiene diferente denominación vigente en el Plan de Estudios, ya sea por traslado interno, de una Escuela Profesional a otra o cambio de sistema curricular en la misma Escuela Profesional.','00',1),('PA884017485','DESIGNACIÓN DE JURADOS, FIJACION DE FECHA, HORA Y LUGAR PARA SUSTENTACION DE TESIS, EXAMEN DE SUFICIENCIA PROFESIONAL O EXAMEN POR SERVICIOS PROFESIONALES','Designación de jurados y determinación de Fecha, Hora y Lugar para Sustentación de Tesis o Examen de Suficiencia Profesional o Examen por Servicios a Nivel Profesional.','00',1),('PA884017516','TRASLADO INTERNO INTER SEDES, ESCUELAS PROFESIONALES Y FACULTADES','Procedimiento mediante el cual un estudiante realiza el cambio de registro de matrícula de una Sede a otra, de una Escuela Profesional a otra, sea dentro de la misma Facultad u otra diferente pertenecientes al mismo grupo de Estudios Generales. El Vicerrectorado Académico verifica el cumplimiento de los requisitos y emite una resolución de traslado.',NULL,1),('PA884017C6F','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO EXTRAORDINARIO  - (CONCURSO DE TALENTOS E HIJOS DE BENEFACTORES DE LA UNDQT.','Dirigido a hijos de benefactores de la UNDQT que lograron alto rendimiento en el concurso de Talentos del Arte elegidos para el presente concurso.','00',1),('PA884018136','CONVALIDACIÓN POR ASIGNATURA','Procedimiento mediante el cual el alumno solicita la convalidación de asignaturas, en el que se verifica la correspondencia de los contenidos silábicos desarrollados en asignaturas afines con los estudios realizados de la Universidad, de aquelallas asignaturas pertenecientes a un plan de estudios de una determinada escuela o programa, cursada y aprobadas por un estudiante en otra universidad nacional, particular o extranjera y otra escuela o especialidad de la ESABAC y/o UNDQT. El Decano verifica el cumplimiento de los requisitos y autoriza la Resolución de la Convalidación de Asignaturas.','00',1),('PA88401827E','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO ORDINARIO - ADMISIÓN ORDINARIO','Procedimiento a través del cual, el estudiante que concluyó satisfactoriamente estudios de Educación Secundaria, se inscribe en esta Modalidad para rendir la Prueba General de Selección Múltiple de Aptitudes y Conocimientos, para alcanzar vacante en la Escuela Profesional a la cual postula. Postulan a esta modalidad, estudiantes que han egresado del nivel secundario de educación básica regular.','00',1),('PA884018DF6','MATRÍCULA DE INGRESANTE (Incluye Carné Universitario y de Biblioteca)','Procedimiento mediante el cual el alumno e un acto formal voluntario se matricula al ingresar a la UNDQT. Es incondicional y conlleva el compromiso de cumplir con las disposiciones establecidas pro la ley Universitaria, Ley N° 30220, el Estatuto de la Universidad, el reglamento y otras normas internas aprobadas por la Universidad. La matrícula es semestral. El centro de Computo verifica el cumplimiento de los requisitos y registra su matrícula.',NULL,1),('PA8840199CF','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO EXTRAORDINARIO  - PERSONAS CON HABILIDADES DIFERENTES','Podrán postular por esta modalidad las personas que según ley Nº 27050, sean declaradas personas con habilidades diferentes, que hayan concluido estudios secundarios satisfactoriamente. Procedimiento a través del cual, el estudiante que concluyó estudios de educación secundaria, en su condición de Persona con Discapacidad inscrito en el Registro Nacional de la Persona con Discapacidad, organizado y actualizado por el Consejo Nacional para la Integración de la Persona con Discapacidad- CONADIS, se inscribe en esta modalidad especial para ocupar una plaza reservada según el porcentaje asignado','00',1),('PA884019CEF','REVISIÓN Y CALIFICACION DE EXPEDIENTES PARA OPTAR EL TITULO PROFESIONAL MODADLIDAD DE SUSTENTACION DE TESIS','Procedimiento a través del cual el bachiller solicita ser declarado apto, previa calificación de expediente para optar al Título Profesional, modalidad de Sustentación de Tesis, consiste en el desarrollo de un trabajo de investigación dentro de las distintas áreas del conocimiento de la Escuela Profesional respectiva y sustentado en acto público; que otorga la UNDQT a nombre de la Nación.','00',1),('PA884019F6A','CERTIFICADO DE ESTUDIOS POR SEMESTRE ACADEMICO SEGUNDA ESPECIALIDAD','Procedimiento a través del cual el estudiante solicita su certificado de estudios, documento que proporciona información oficial sobre los promedios finales de las asignaturas del Plan de Estudios, cursadas por el estudiante en su Segunda Especialidad Profesional. Se expide el Certificado por semestre académico previa verificación de los requisitos exigidos.','00',1),('PA88401A16F','REVALIDACIÓN DE GRADOS Y TÍTULOS','Procedimiento en el que el administrado solicita revalidación de Grados y Títulos, a través del cual se otorga efecto en territorio nacional al Grado o Título conferido por una institución educativa de rango universitario, como consecuencia de haber superado una evaluación académica realizada por una universidad licenciada para prestar el servicio educativo superior universitario en el Perú. El especialista del rectorado verifica el cumplimiento de los requisitos exigidos y emite la Resolución debidamente firmada por los responsables.','00',1),('PA88401A1D3','CALIFICACIÓN DE EXPEDIENTE PARA OPTAR;  EL TITULO DE PROFESIONAL MODALIDAD DE SERVICIOS PROFESIONALES','Procedimiento mediante el cual, el bachiller solicita ser declarado Apto, previa calificación de expediente para optar al Título Profesional, modalidad de Servicios a Nivel Profesional- Experiencia Profesional, consistente en la acumulación de un mínimo de tres años de actividad profesional en labores propias de la especialidad, desarrollado en un Proyecto donde ha cumplido un rol importante y previa sustentación oral. Esta modalidad solo es aplicable a quienes ingresaron antes del primer Semestre del 2014.','00',1),('PA88401A2FF','CERTIFICADO DE ESTUDIOS POR SEMETRE-SISTEMATIZADO','Procedimiento mediante el cual el alumno solicita Certificado de Estudios, documento oficial que acredita los estudios que el alumno ha cursado y superado con éxito. Documento que proporciona información oficial sobre los promedios finales de las asignaturas del Plan de Estudios, cursadas por el estudiante de su Escuela Profesional. Se expide por semestre académico. El decano verifica el cumplimiento de los requisitos y autoriza elaborar el certificado de estudios.',NULL,1),('PA88401BACA','MATRICULA REGULAR SEGUNDA ESPECIALIDAD PROFESIONAL','Procedimiento a través del cual, el postulante que ha alcanzado una plaza vacante a la Segunda Especialidad Profesional, activa su matrícula previa generación de código por el Centro de Cómputo e ingreso de asignaturas que forman parte del Plan de Estudios, para el semestre correspondiente. El decano de la facultad revisa el cumplimiento de los requisitos y autoriza la matrícula regular en segunda especialidad profesional.','00',1),('PA88401C844','MATRÍCULA DE GRADUADOS Y/O TITULADOS.','Procedimiento mediante el cual una persona natural solicita matrícula de Graduado o Titulado. El graduado o titulado que alcanza vacante en esa modalidad de admisión, registra matrícula dentro del cronograma aprobado, previa asignación del código de estudiante que realiza el Centro de Cómputo. El graduado o titulado que haya obtenido vacante mediante esa modalidad presenta la certificación de vacante. El Decano de la Facultad verifica el cumplimiento de los requisitos y autoriza la matrícula mediante resolución disponiendo, además, que el Centro de Cómputo proceda al registro.','00',1),('PA88401D2A7','CONSTANCIA DE EGRESADO','Procedimiento a través del cual el administrado, solicita la expedición de dicho documento, para acreditar su situación académica. El decano de la Facultad verifica el cumplimiento de los requisitos y autoriza la constancia de egresado.','00',1),('PA88401D64F','CALIFICACIÓN DE EXPEDIENTE PARA OPTAR; EL TITULO DE PROFESIONAL MODALIDAD DE SUFICIENCIA PROFESIONAL','Procedimiento a través del cual el bachiller solicita ser declarado Apto, previa calificación de expediente para optar al Título Profesional, modalidad de Suficiencia Profesional, mediante presentación de documento escrito y posterior presentación oral del mismo o evaluación del contenido de materias de formación profesional, previamente sorteada y presentada de manera oral en acto público; que otorga la UNDQT a nombre de la Nación.','00',1),('PA88401E411','INSCRIPCIÓN AL PROCESO DE ADMISION POR CONCURSO EXTRAORDINARIO -  HIJOS DE INDIGENAS Y NATIVOS','La presente exoneración comprende también para los hijos de los indígenas alto andinos y de la zona selvática de la Región del Cusco, siempre y cuando tengan notas sobresalientes en el área de arte obtenidos durante el último año inmediato anterior de estudios del nivel secundario.','00',1),('PA88401ECB5','REINICIO DE ESTUDIOS DE 5 A 6 SEMESTRES','Procedimiento mediante el cual el alumno solicita reinicio de estudios. El reinicio de estudios lo solicita el estudiante que ha dejado de matricularse en cinco a seis semestres. El Decano de la Facultad verifica el cumplimiento de los requisitos y autoriza la Resolución de reinicio de estudios.','00',1),('PA88401F560','PAGO POR ASIGNATURA DESAPROBADA: NO SE PRESENTO, IMPEDIDOS','Procedimiento a través del cual, el administrado (estudiante) solicita matrícula con pleno conocimiento de condicionamiento a superar el bajo récord académico.','00',1),('PA88401F5E7','DUPLICADO DE DIPLOMA DE GRADO O TÍTULO; POR MOTIVO DE PERDIDA DEL ORIGINAL','Procedimiento mediante el cual el interesado presenta a través de la Unidad de Trámite Documentario solicitud dirigida al Rector, peticionando la emisión de duplicado de diploma de grado académico, título profesional o título de segunda especialidad, según sea el caso, por motivo de pérdida del original. El decano de la facultad recibe la solicitud y lo deriva a secretaría General para su revisión en los Libros de Registro de Grados y Títulos de la Universidad quien después de verificar su conformidad emite informe al Consejo Universitario para que emita la resol. de Emisión y rotulado del Diploma con sello de DUPLICADO al margen izquierdo.','00',1),('PA88401F79C','INSCRIPCIÓN AL PROCESO DE ADMISIÓN POR CONCURSO EXTRAORDINARIO   - ADMISION DE TRASLADOS EXTERNOS','Las vacantes paa postulantes en la modalidad de traslados externos de cualquier Universidad y/o Escuelas de Arte con nivel universitario de pais o del extranjero, son evaluados y aprobados por Vice Presidencia Académica.','00',1),('PE123299E43','ACCESO A LA INFORMACION PÚBLICA CREADA U OBTENIDA POR LA ENTIDAD, QUE SE ENCUENTRA EN SU POSESIÓN O BAJO SU CONTROL','Procedimiento a través del cual toda persona, natural o jurídica, solicita información pública(información creada, obtenida, en posesión o bajo control de una entidad pública), sin expresar la causa de su pedido, y la recibe en la forma o medio solicitado, siempre que asuma el costo de su reproducción física o de manera gratuita cuando se solicite que esta sea entregada pro medio virtual. El plazo de atención es de 10 días hábiles, sin embargo, cuando sea materialmente imposible cumplir con el plazo señalado debido a causas justificadas, por única vez la entidad comunica al solicitante la fecha en que proporcionará la información solicitada de forma debidamente fundamentada, en un plazo de dos (2) días hábiles de recibido el pedido de información.',NULL,1),('SE8840108D1','CONSTANCIA DE INGRESO','Servicio exclusivo mediante el cual el administrado solicita un documento que da constancia de que el usuario ha accedido a una vacante en alguna de las carreras profesionales por laUNDQT en el examen de adminisión respectivo, no es renovable y se da por una sola vez.','00',1),('SE8840109FC','RECORD ACADÉMICO','PROCEDIMIENTO A TRAVES DEL CUAL, EL ESTUDIANTE OBTIENE EL REPORTE DEL CÓDIGO, CATEGORIA DE LAS ASIGNATURAS Y NOTAS CURSADAS PRO SEMESTRE ACADÉMICOS, DE ACUERDO AL PLAN DE ESTUDIOS. EL CENTRO DE COMPUTO, VERIFICA EL CUMPLIMIENTO DE LOS REQUISITOS Y EMITE EL RECORD ACADÉMICO.','00',1),('SE884011FD4','CONSTANCIA DE BUENA CONDUCTA','Procedimiento mediante el cual el alumno solicita constancia de buena conducta documento que acredita que el alumno ha respetado el reglamento académico con buena conducta en su permanencia en la universidad. El Director de la Escuela verifica el cumplimiento de los requisitos y autoriza se otorgue la constancia.','00',1),('SE88401343C','CONSTANCIA DE NO DEUDOR (ESTUDIANTES PREGRADO)','Procedimiento mediante el cual el administrado solicita Constancia de no deudor, a través del cual, se establece la existencia de alguna carencia pendiente de pago, o bien utilizado no devuelto y que el administrado necesita poseer para realizar trámites de su interés. La Dirección de asuntos Académicos revisa el cumplimiento de los requisitos y otorga la constancia de no deudor.','00',1),('SE8840162BE','RECTIFICACIÓN DE NOMBRES Y APELLIDOS POR MANDATO JUDICIAL, NOTARIAL O ADMINISTRATIVO','Procedimiento mediante el cual el administrado solicita se rectifica o corrige el Nombre del administrado por mandato Judicial, Notarial y /o Administrativo: La solicitud es considerada aprobada desde el mismo momento de su presentación ante la entidad competente para conocerla, siempre que el administrado cumpla con los requisitos y entregue documentación completa, exigidos.','00',1),('SE884016E56','CERTIFICACION DE COPIA DE DIPLOMA','Procedimiento a través del cual el administrado solicita certificación de copia de diploma. El Secretario General de la UNDQT previa verifica el cumplimiento de los requisitos y certifica la copia de Diploma, solicitado por el graduado, para trámites de su interés.','00',1),('SE884016FBD','COPIA VISADA DE SILABOS POR ASIGNATURA','Procedimiento a través del cual, el administrado solicita la expedición de copia visada de sílabo, para los fines que viere por conveniente. Sílabo es el documento que contiene toda la información necesaria sobre la asignatura: objetivos, contenidos, secuencia didáctica, metodologías, mecanismos de evaluación y referencias bibliográficas. La Dirección de Escuela Profesional verifica el cumplimiento de los requisitos y autoriza la dación de la copia visada de sílabos por asignatura.','00',1),('SE884017A87','CARNET DE BIBLIOTECA ALUMNOS REGULARES','Procedimiento a través del cual se otorga Carné de Lector de Biblioteca a los alumnos regulares de la UNDQT, para hacer uso de este servicio.','00',1),('SE884017E1E','DUPLICADO DE CONSTANCIAS DE NOTAS','Procedimiento a través del cual el administrado, solicita la expedición de dicho documento, que acredita su condición de estudiante, para trámites que viera por conveniente. La dirección de la Escuela Profesional verifica el cumplimiento de los requisitos y autoriza el duplicado de Constancia de Notas.','00',1),('SE884017E35','JURAMENTACIÓN O PROMESA DE HONOR PARA TITULADOS (PREGRADO) (INCLUYE TOGA, BIRRETE, PORTA TITULO, MEDALLA)','Procedimiento mediante el cual el administrado solicita juramentación o promesa de honor para pregrado o postgrado, acto de titulación y juramentación o promesa de honor de quien resulte aprobado (es optativo). Se realiza en acto público presidido por el Decano en representación del Rector y asistencia de docentes.','00',1),('SE884018286','CONSTANCIA DE ESTUDIOS','Procedimiento mediante el cual el administrado solicita constancia de estudios documento que acredita la situación académica del estudiante a la fecha de la solicitud dirigido a estudiantes de pregrado y posgrado. La Dirección de asuntos académicos verifica el cumplimiento de los requisitos y emite la constancia de Estudios.','00',1),('SE88401C3F0','CARNE UNIVERSITARIO','Procedimiento a través del cual la Dirección de Registro y Servicios Académicos, hace entrega del Carné Universitario emitido para alumnos de matrícula vigente, Documento que acredita su condición del estudiante de la UNDQT. El servidor que atiende este procedimiento verifica el cumplimiento de los requisitos y otorga el carne universitario.',NULL,1),('SE88401D62D','DUPLICADO DE CARNET DE POSTULANTE','El postulante a Examen de Admisión solicita duplicado de carné y/o constancia por pérdida, requisito indispensable para rendir la prueba. Es expedido por la Dirección General de Admisión.','00',1),('SE88401D909','DUPLICADO DE CONSTANCIAS DE MATRÍCULA','Procedimiento a través del cual el administrado, solicita la expedición del duplicado de dicho documento, que acredita su condición de estudiante, para trámites que viera por conveniente. La dirección de la escuela profesional verifica el cumplimiento de los requisitos y autoriza el duplicado de Constancia de Matrícula.','00',1),('SE88401DEFB','CONSTANCIA DE EGRESADO SEGUNDA ESPECIALIDAD','Procedimiento mediante el cual el administrado solicita Constancia de Egresado de Segunda especialidad. La Dirección de la Escuela Profesional o post grado verifica el cumplimiento de los requisitos y autoriza la expedición de la Constancia de Egresado.','00',1),('SE88401FD77','CARNET DE BIBLIOTECA EGRESADOS Y DOCENTES','Procedimiento mediante el cual el administrado solicita carné de Biblioteca, se otorga Carné de Lector de Biblioteca al egresados y docentes de la UNDQT, para hacer uso de este servicio.','00',1);
