CREATE DEFINER=`root`@`localhost` PROCEDURE `tupa_listar_unidades_por_tramite_para_seleccionar`(      
     pcodigo varchar(20)
)
BEGIN
   select ut.ccodigo, 
		uo.nidtunidadorganizativa,uo.cnombreunidadorganizativa 
   from (select * from tunidadtramite where ccodigo=pcodigo) ut
