CREATE DEFINER=`root`@`localhost` PROCEDURE `tupa_sp_iniciar_sesion`(      
	pclogin varchar(20),
    pcontrasenia varchar(200)
)
BEGIN	
	select u.* 
    from tusuario u inner join  tlogin l 
    on u.cidtusuario=l.cidtusuario
