    if (opcion='D') THEN
          DELETE from trequisitotramite where nidtrequisitotramite=pnidtrequistotramite;
          select pnidtrequistotramite as ncodigo,"CORRECTO" as cestado,'ELIMINADO' AS cmensaje;
    END IF;
END ;;
DELIMITER ;
